18	// Firestore error handler
19	export enum OperationType {
20	  CREATE = 'create',
21	  UPDATE = 'update',
22	  DELETE = 'delete',
23	  LIST = 'list',
24	  GET = 'get',
25	  WRITE = 'write',
26	}
27	
28	export interface FirestoreErrorInfo {
29	  error: string;
30	  operationType: OperationType;
31	  path: string | null;
32	  authInfo: {
33	    userId: string | undefined;
34	    email: string | null | undefined;
35	    emailVerified: boolean | undefined;
36	    isAnonymous: boolean | undefined;
37	    tenantId: string | null | undefined;
38	    providerInfo: {
39	      providerId: string;
40	      displayName: string | null;
41	      email: string | null;
42	      photoUrl: string | null;
43	    }[];
44	  }
45	}
46	
47	export function handleFirestoreError(error: unknown, operationType: OperationType, path: string | null) {
48	  const errInfo: FirestoreErrorInfo = {
49	    error: error instanceof Error ? error.message : String(error),
50	    authInfo: {
51	      userId: auth.currentUser?.uid,
52	      email: auth.currentUser?.email,
53	      emailVerified: auth.currentUser?.emailVerified,
54	      isAnonymous: auth.currentUser?.isAnonymous,
55	      tenantId: auth.currentUser?.tenantId,
56	      providerInfo: auth.currentUser?.providerData.map(provider => ({
57	        providerId: provider.providerId,
58	        displayName: provider.displayName,
59	        email: provider.email,
60	        photoUrl: provider.photoURL
61	      })) || []
62	    },
63	    operationType,
64	    path
65	  }
66	  console.error('Firestore Error: ', JSON.stringify(errInfo));
67	  throw new Error(JSON.stringify(errInfo));
68	}
